SELECT DISTINCT m.id, m.parent_id AS parentId, m.menu_name AS menuName, m.menu_type AS menuType, m.path, m.component, m.perms, m.icon, m.sort_order AS sortOrder, m.visible, m.create_time AS createTime FROM sys_menu m INNER JOIN sys_role_menu rm ON rm.menu_id = m.id AND rm.deleted = 0 WHERE m.deleted = 0 AND rm.role_id IN
#{rid}
ORDER BY m.sort_order ASC, m.id ASC
